import createReducer from '~/redux/store/createReducer';
import { Action } from 'redux';

export type GetVirtualCardCallback = (data: {
  statusCode: number | undefined;
  response: GetVirtualCardCVVReturn['data'] | undefined;
}) => void;

export enum VirtualCardTypes {
  GET_VIRTUAL_CARD = '@virtualCard/GETVIRTUALCARD',
  GET_VIRTUAL_CARD_SUCCESS = '@virtualCard/GETVIRTUALCARDSUCCESS',
  GET_VIRTUAL_CARD_ERROR = '@virtualCard/GETVIRTUALCARSERROR',
  GET_VIRTUAL_CARD_CVV_SUCCESS = '@virtualCard/GETVIRTUALCARDCVVSUCCESS',
  GET_VIRTUAL_CARD_CVV = '@virtualCard/GETVIRTUALCARDCVV',
  CLEAN_VIRTUAL_CARD = '@virtualCard/CLEANVIRTUALCARD',
}

export interface GenerateVirtualCardResponse {
  code: number;
  message: string;
  data: {
    Cartao: string;
  };
}
export interface GenerateVirtualCardRequest {
  CPF: string | undefined;
  Conta: string;
}

export interface GetVirtualCardCVVReturn {
  code: number;
  message: string;
  data: {
    CartaoVirtual: {
      NomePortador: string;
      NumeroCartao: string;
      Validade: string;
      Cvv: string;
      Chave: string;
      ValidadeCvv: string;
      HoraValidadeCvv: string;
    };
  };
}
export interface VirtualCardReducerProps {
  isLoadingCVV: boolean;
  isLoading: boolean;
  isError: boolean;
  cardNumber: string;
}

type State = VirtualCardReducerProps;

export const initialState: VirtualCardReducerProps = {
  cardNumber: '',
  isError: false,
  isLoading: false,
  isLoadingCVV: false,
};

export type virtualCardCallback = (data: {
  statusCode: number | undefined;
  response: GenerateVirtualCardResponse | undefined;
}) => void;

const virtualCardReducer = createReducer(initialState, {
  [VirtualCardTypes.GET_VIRTUAL_CARD](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [VirtualCardTypes.GET_VIRTUAL_CARD_SUCCESS](
    state: State,
    { cardNumber }: { cardNumber: string },
  ): State {
    return {
      ...state,
      isLoading: false,
      cardNumber,
    };
  },
  [VirtualCardTypes.GET_VIRTUAL_CARD_ERROR](state: State): State {
    return {
      ...state,
      isError: true,
      isLoading: false,
      isLoadingCVV: false,
    };
  },
  [VirtualCardTypes.GET_VIRTUAL_CARD_CVV](state: State): State {
    return {
      ...state,
      isLoadingCVV: true,
    };
  },
  [VirtualCardTypes.GET_VIRTUAL_CARD_CVV_SUCCESS](state: State): State {
    return {
      ...state,
      isLoadingCVV: false,
      isError: false,
    };
  },
  [VirtualCardTypes.CLEAN_VIRTUAL_CARD](): State {
    return initialState;
  },
});

interface VirtualCardActions {
  putVirtualCard: (
    data: GenerateVirtualCardRequest,
    callback: virtualCardCallback,
  ) => Action;
  getVirtualCardSuccess: (cardNumber: string) => Action;
  getVirtualCardError: () => Action;
  getVirtualCardCVV: (
    encryptedCrad: string,
    callback: GetVirtualCardCallback,
  ) => Action;
  getVirtualCardCVVSuccess: () => Action;
  cleanVirtualCard: () => Action;
}

export const virtualCardActions: VirtualCardActions = {
  putVirtualCard: (data, callback) => ({
    type: VirtualCardTypes.GET_VIRTUAL_CARD,
    data,
    callback,
  }),
  getVirtualCardSuccess: cardNumber => ({
    type: VirtualCardTypes.GET_VIRTUAL_CARD_SUCCESS,
    cardNumber,
  }),
  getVirtualCardError: () => ({
    type: VirtualCardTypes.GET_VIRTUAL_CARD_ERROR,
  }),
  getVirtualCardCVV: (lastFourNumbers, callback) => ({
    type: VirtualCardTypes.GET_VIRTUAL_CARD_CVV,
    lastFourNumbers,
    callback,
  }),
  getVirtualCardCVVSuccess: () => ({
    type: VirtualCardTypes.GET_VIRTUAL_CARD_CVV_SUCCESS,
  }),
  cleanVirtualCard: () => ({
    type: VirtualCardTypes.CLEAN_VIRTUAL_CARD,
  }),
};

export default virtualCardReducer;

